    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_DERIVATIVES(N_CLEARED_TXN_BANK_ROLE_ID,N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,N_D_CUST_INDUSTRY_SKEY,N_INSTRUMENT_SKEY,N_ISSUE_SKEY,N_ORIG_NETTING_AGREEMENT_SKEY,F_CORE_INVESTMENT_COMPANY_IND,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,F_CLEARED_TXN_COLLATERAL,F_COUNTERPARTY_CMC_FLAG,F_EXP_FUND_CCY_SAME_IND,F_INSTR_ULY_CCY_SAME_IND,F_INTERNAL_CUST_IND,F_PARENT_FIDUCIARY_ACCT_IND,F_QUALIFIED_CCP_FLAG,F_REGULATORY_PARTY_INDICATOR,F_TREASURY_STOCK_INDICATOR,N_BASEL_SECTOR_SKEY,N_CENTRAL_COUNTERPARTY_SKEY,N_CLEARING_MEMBER_SKEY,N_CURR_12M_ECL,N_EFF_MATURITY,N_EXCHANGE_RATE,N_EXPOSURE_AMOUNT,N_EXP_MTM_VALUE,N_FIRM_SIZE,N_GENERAL_PROVISION_AMT,N_GROUP_ASSET_SIZE,N_INCURRED_CVA_AMOUNT,N_LATEST_MATURITY,N_LOSS_ALLOWANCE_LIFE_ECL,N_MARKET_VALUE,N_NETTING_AGREEMENT_SKEY,N_NOTIONAL_PRINCIPAL,N_ORIGINAL_MATURITY,N_INSTR_OTH_VALUATION_ADJ_AMT,N_PARENT_ACCT_SKEY,N_PARENT_FIDUCIARY_ACCT_SKEY,N_PROVISION_AMOUNT,N_RESIDUAL_MATURITY,N_RUN_SKEY,N_CUST_ANNUAL_SALES,N_SHAREHOLDING_PERCENT,N_TIME_TO_START,N_UNDERLYING_RESIDUAL_MATURITY,N_UNDRAWN_AMOUNT,N_UNPAID_PREMIUM,N_INSTR_VALUATION_ADJ_AMOUNT,N_VALUE_DATE_SKEY,N_WRITE_OFF_AMT,V_DATA_SOURCE,V_EXP_RCY_CODE,N_ENTITY_SKEY,F_CASH_POOL_DAILY_TRANSFER,F_CASH_POOL_LEGAL_ENFORCEABLE,F_CREDIT_IMPAIRMENT_FLAG,F_EXP_TREATED_AS_HIGH_RISK,F_FINANCIAL_ASSET_IFRS9_FLAG,N_ADJUSTED_LGD_PERCENT,N_DVA_AMOUNT,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,V_APPROACH_TYPE,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_STD_COMMODITY_SKEY,N_INSTR_TYPE_SKEY,N_UNDERLYING_TYPE_SKEY,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_REG_CAP_INDUSTRY_SKEY,N_REG_INDUSTRY_SKEY,N_BASEL_PROD_TYPE_SKEY,N_RUN_PARAMETER_SETUP_SKEY,D_EXPOSURE_START_DATE,F_BUYER_SELLER_IND,F_CLEARED_TRANSACTION_FLAG,F_DVP_FLAG,F_FAILED_TRADE_FLAG,F_ILLIQUID_DERIVATIVES,F_MARGINED_TXN_IND,F_MATERI