ARTY_TYPE_SECTOR_RECLASS.N_BASEL_SECTOR_SKEY, FSI_CAP_INDUS_SECTOR_RECLASS.N_BASEL_SECTOR_SKEY),DIM_PARTY_CCP.n_party_skey,DIM_PARTY_CM.n_party_skey,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,CASE WHEN FSI_ACCT_MODELING_INFO.N_EFF_MATURITY IS NULL THEN DAYS_BETWEEN(STG_CREDIT_DERIVATIVES.FIC_MIS_DATE,STG_CREDIT_DERIVATIVES.D_MATURITY_DATE,CASE WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'A/360' THEN 'Actual/360' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'A/365F' THEN 'Actual/365 (Fixed)' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'A/A' THEN 'Actual/Actual' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'B/252' THEN 'Business/252' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = '30/360' THEN 'Thirty/360' END) ELSE FSI_ACCT_MODELING_INFO.N_EFF_MATURITY END,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_CREDIT_DERIVATIVES.N_CD_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_CREDIT_DERIVATIVES.N_MTM_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_CAP_PARTY_FINANCIALS.N_TOTAL_ASSETS * A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_ACCT_MODELING_INFO.N_STAGE_I_ALLOWANCES + FSI_ACCT_MODELING_INFO.N_STAGE_II_ALLOWANCES,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_CREDIT_DERIVATIVES.N_INCURRED_CVA_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,GREATEST(DAYS_BETWEEN(STG_CREDIT_DERIVATIVES.FIC_MIS_DATE, GREATEST(STG_CREDIT_DERIVATIVES.D_MATURITY_DATE, COALESCE(STG_UNDERLYING_DTL.D_MATURITY_DATE,STG_CREDIT_DERIVATIVES.D_MATURITY_DATE)), STG_CREDIT_DERIVATIVES.V_DAY_COUNT_IND),10/(CASE WHEN FSI_RUN_PARAMETER.V_MPOR_CALC_BASIS = 'OPTDAY01' THEN DECODE(FSI_RUN_PARAMETER.V_NO_OF_BUSINESS_DAYS,'OPTDAY03',250,'OPTDAY04',252) ELSE 365 END)),CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,STG_CREDIT_DERIVATIVES.N_MARKET_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,COALESCE(DIM_NETTING_AGREEMENT.N_NETTING_AGREEMENT_SKEY, DUMMY_NETTING_AGREEMENT.N_NETTING_AGREEMENT_SKEY, 0),STG_CREDIT_DERIVATIVES.N_NOTIONAL_AMT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,DAYS_BETWEEN(STG_CREDIT_DERIVATIVES.D_EFFECTIVE_DATE, STG_CREDIT_DERIVATIVES.D_MATURITY_DATE, CASE WHEN STG_CREDIT_DERIVATIVES.V_DAY_COUNT_IND = 'A/360' THEN 'ACTUAL/360' WHEN STG_CREDIT_DERIVATIVES.V_DAY_COUNT_IND = 'A/365F' THEN 'ACTUAL/365 (FIXED)' WHEN STG_CREDIT_DERIVATIVES.V_DAY_COUNT_IND = 'A/A' THEN 'ACTUAL/ACTUAL' WHEN STG_CREDIT_DERIVATIVES.V_DAY_COUNT_IND = 'B/252' THEN 'BUSINESS/252' WHEN STG_CREDIT_DERIVATIVES.V_DAY_COUNT_IND = '30/360' THEN 'THIRTY/360' END),FSI_INSTR_VALUATION_DETAILS.N_OTHER_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,DIM_PARENT_EXPOSURE.n_acct_skey,DIM_EXPOSURE_CUST.N_ACCT_SKEY,STG_CREDIT_DERIVATIVES.N_PROVISION_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,DAYS_BETWEEN(STG_CREDIT_DERIVATIVES.FIC_MIS_DATE,STG_CREDIT_DERIVATIVES.D_MATURITY_DATE,CASE WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'A/360' THEN 'Actual/360' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'A/365F' THEN 'Actual/365 (Fixed)' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'A/A' THEN 'Actual/Actual' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'B/252' THEN 'Business/252' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = '30/360' THEN 'Thirty/360' END),'870',FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,CASE WHEN STG_CREDIT_DERIVATIVES.FIC_MIS_DATE > LEAST(STG_CREDIT_DERIVATIVES.D_EFFECTIVE_DATE, COALESCE(STG_UNDERLYING_DTL.D_EFFECTIVE_DATE,STG_CREDIT_DERIVATIVES.D_EFFECTIVE_DATE)) THEN 0 ELSE CASE WHEN DAYS_BETWEEN(STG_CREDIT_DERIVATIVES.FIC_MIS_DATE, LEAST(STG_CREDIT_DERIVATIVES.D_EFFECTIVE_DATE, COALESCE(STG_UNDERLYING_DTL.D_EFFECTIVE_DATE,STG_CREDIT_DERIVATIVES.D_EFFECTIVE_DATE)), STG_CREDIT_DERIVATIVES.V_DAY_COUNT_IND) < 10 / 365 THEN 10 / 365 ELSE DAYS_BETWEEN(STG_CREDIT_DERIVATIVES.FIC_MIS_DATE, LEAST(STG_CREDIT_DERIVATIVES.D_EFFECTIVE_DATE, COALESCE(STG_UNDERLYING_DTL.D_EFFECTIVE_DATE,STG_CREDIT_DERIVATIVES.D_EFFECTIVE_DATE)), STG_CREDIT_DERIVATIVES.V_DAY_COUNT_IND) END END,(STG_UNDERLYING_DTL.D_MATURITY_DATE -  STG_CREDIT_DERIVATIVES.FIC_MIS_DATE) / 365,STG_CREDIT_DERIVATIVES.N_UNDRAWN_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_CREDIT_DERIVATIVES.N_UNPAID_PREMIUM * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_INSTR_VALUATION_DETAILS.N_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,(SELECT N_DATE_SKEY FROM DIM_DATES WHERE D_CALENDAR_DATE = STG_CREDIT_DERIVATIVES.D_VALUE_DATE),STG_CREDIT_DERIVATIVES.N_WRITE_OFF_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,'STG_CREDIT_DERIVATIVES',FSI_CAP_RUN_EXE_PARAMETERS.V_RCY_CODE,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),FSI_ACCT_MODELING_INFO.F_CASH_POOL_DAILY_TRANSFER,FSI_ACCT_MODELING_INFO.F_CASH_POOL_LEGAL_ENFORCEABLE,FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_EXP_TREATED_AS_HIGH_RISK,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,to_char(FSI_ACCT_MODELING_INFO.N_ADJUSTED_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_DVA_AMOUNT),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_COMMODITY_CLASSIFICATION.N_STD_COMMODITY_SKEY),to_char(FSI_INSTR_TYPE_CLASSIFICATION.N_STD_INSTR_TYPE_SKEY),to_char(FSI_