DGE_PORTFOLIO_SET ON STG_CREDIT_DERIVATIVES.V_HEDGE_PORTFOLIO_SET_CODE = DIM_HEDGE_PORTFOLIO_SET.V_HEDGE_PORTFOLIO_SET_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_HEDGE_PORTFOLIO_SET.D_RECORD_START_DATE AND DIM_HEDGE_PORTFOLIO_SET.D_RECORD_END_DATE LEFT JOIN DIM_HEDGED_RISK ON DIM_HEDGED_RISK.V_HEDGED_RISK_CODE = 'CVARSK' AND to_date('20260331','YYYYMMDD') BETWEEN DIM_HEDGED_RISK.D_RECORD_START_DATE AND DIM_HEDGED_RISK.D_RECORD_END_DATE LEFT JOIN DIM_REG_CAP_INDUSTRY ON DIM_REG_CAP_INDUSTRY.N_REG_CAP_INDUSTRY_SKEY = FSI_REG_CAP_INDUSTRY_RECLASS.N_REG_CAP_INDUSTRY_SKEY LEFT JOIN FSI_CAP_INDUS_SECTOR_RECLASS ON FSI_CAP_INDUS_SECTOR_RECLASS.N_RUN_SKEY = '870' AND FSI_CAP_INDUS_SECTOR_RECLASS.V_GICS_INDUSTRY_CODE = DIM_REG_CAP_INDUSTRY.V_GICS_INDUSTRY_CODE LEFT JOIN DIM_STANDARD_PARTY_TYPE ON DIM_STANDARD_PARTY_TYPE.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT JOIN FSI_PARTY_TYPE_SECTOR_RECLASS ON FSI_PARTY_TYPE_SECTOR_RECLASS.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_SECTOR_RECLASS.N_STD_PARTY_TYPE_SKEY = DIM_STANDARD_PARTY_TYPE.N_STANDARD_PARTY_TYPE_SKEY LEFT JOIN FSI_RUN_PARAMETER ON FSI_RUN_PARAMETER.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = FSI_RUN_PARAMETER.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN FSI_PROD_TXN_TYPE_RECLASS ON FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY = DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY AND FSI_PROD_TXN_TYPE_RECLASS.N_RUN_SKEY = '870' WHERE 1=1 AND 1=1 AND COALESCE(STG_CREDIT_DERIVATIVES.F_CAPITAL_CHARGE_EXCLUSION, 'N') <> 'Y' AND COALESCE(STG_CREDIT_DERIVATIVES.D_ACCT_CLOSED_DATE, STG_CREDIT_DERIVATIVES.FIC_MIS_DATE) >= STG_CREDIT_DERIVATIVES.FIC_MIS_DATE AND EXISTS ( SELECT 1 FROM FSI_CAP_ACCOUNT_LOAD_RUN_MAP WHERE FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_ACCOUNT_NUMBER = STG_CREDIT_DERIVATIVES.V_ACCOUNT_NUMBER AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = STG_CREDIT_DERIVATIVES.FIC_MIS_DATE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_GAAP_CODE = STG_CREDIT_DERIVATIVES.V_GAAP_CODE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_LOAD_RUN_ID = STG_CREDIT_DERIVATIVES.N_LOAD_RUN_ID ) AND DAYS_BETWEEN(STG_CREDIT_DERIVATIVES.FIC_MIS_DATE, STG_CREDIT_DERIVATIVES.D_MATURITY_DATE, CASE WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'A/360' THEN 'Actual/360' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'A/365F' THEN 'Actual/365 (Fixed)' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'A/A' THEN 'Actual/Actual' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = 'B/252' THEN 'Business/252' WHEN STG_CREDIT_DERIVATIVES.v_day_count_ind = '30/360' THEN 'Thirty/360' END) > 0 AND 1= CASE WHEN ( FSI_BASEL_EXEC_APPR_DETAILS.F_PORTFOLIO_BASED_FLAG ='N' ) OR ( FSI_BASEL_EXEC_APPR_DETAILS.F_PORTFOLIO_BASED_FLAG ='Y' AND FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_PORTFOLIO_SKEY IS NOT NULL ) THEN 1 ELSE 2 END  AND NOT EXISTS (select 1 from FSI_HEDGE_PORTFL_SET_ACCT_MAP where FSI_HEDGE_PORTFL_SET_ACCT_MAP.n_run_skey = '870' AND FSI_HEDGE_PORTFL_SET_ACCT_MAP.N_INSTRUMENT_SKEY = DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY and DIM_HEDGE_PORTFOLIO_SET.N_HEDGE_PORTFOLIO_SET_SKEY =FSI_HEDGE_PORTFL_SET_ACCT_MAP.N_HEDGE_PORTFOLIO_SET_SKEY and FSI_HEDGE_PORTFL_SET_ACCT_MAP.V_HEDGED_RISK_CODE=DIM_HEDGED_RISK.V_HEDGED_RISK_CODE) LOG ERRORS INTO FSI_CAP_DERIVATIVES$ ('1776768422872_55159475_20260331_1_Job_cab159666feb48c8a8f639023390c156') REJECT LIMIT 0;

